mermaid:
graph TD
    A["Start: E. coli Iron Homeostasis"] --> B(Environmental Iron Availability (Fe3+));
    A --> C(Dissolved Oxygen Levels);
    B --> D(E. coli Cell);
    C --> D;

    D --> E{Is environmental iron low?};
    E -- Yes --> F[Low Iron Condition];
    E -- No --> G[High Iron Condition];

    F --> H[/Apo-Fur Protein - inactive repressor/];
    G --> I(Intracellular Fe2+ Ion);
    H & I --> J[/Fe2+-Fur Complex - Holo-Fur, active repressor/];

    J --> K(Fur Binding to DNA - Fur-box);
    K --> L[/Transcriptional Repression by Holo-Fur/];
    K --> M[Transcriptional Activation by Holo-Fur (e.g., storage genes)];

    F --> N(Apo-Fur Dissociates from DNA);
    N --> O[/Transcriptional Derepression by Apo-Fur/];

    O --> P[Upregulation of Siderophore Systems (ent, fep)];
    P --> Q[Siderophore Biosynthesis & Secretion Enzymes];
    Q --> R[Siderophores (e.g., Enterobactin)];
    R & B --> S[Iron-Siderophore Complex];
    S --> T[Siderophore Uptake Systems (Fhu, Fec, Fep)];
    T --> U[Cytoplasmic Ferric Iron (Fe3+) from siderophores];

    O --> V[Upregulation of Feo System (Ferrous Iron Uptake)];
    V --> W[FeoAB/C System];
    W --> X[Cytoplasmic Ferrous Iron (Fe2+)];

    O --> Y[Upregulation of Heme Uptake Systems (chu, shu)];
    Y --> Z[Heme Uptake & Iron Release (HemO)];
    Z --> X; 

    U --> AA[Ferric Reductase Activity];
    AA --> X;

    M --> AB[Upregulation of Iron Storage Proteins (ftnA, bfr)];
    AB --> AC[Ferritin (FtnA) & Bacterioferritin (Bfr)];
    AC --> AD[Iron Sequestration & Storage];
    AD --> AE[Stored Iron Pool];

    X --> AF[Iron Utilization for Essential Metalloproteins];
    AF --> AG[Essential Metalloproteins & Cellular Metabolism];

    X --> AH[\Is Cytoplasmic Fe2+ level high?/];
    AH -- Yes --> AI[Fenton Reaction & ROS Production];
    AI --> AJ[Oxidative Damage & Cell Impairment];
    AH -- No --> AF;

    F --> AK[RyhB sRNA Activation (low iron)];
    AK --> AL[/RyhB Repression of Iron-Dependent Enzymes (e.g., sdh, suc)/];
    AL --> AM[Iron Conservation];

    G --> AN[/RyhB sRNA Repression (high iron)/];
    AN --> AO[/Derepression of Iron-Dependent Enzymes/];
    AO --> AF;

    G --> AP[High Iron Promotes Colibactin Production (pks island)];
    AP --> AQ[/Colibactin Genotoxicity/];
    AQ --> AR[Increased DNA Damage];

    C --> AS{Is Dissolved Oxygen high?};
    AS -- Yes --> AT[Disruption of Iron Homeostasis];
    AT --> AU[Increased Oxidative Stress/Iron Deficiency Symptoms];
    AU --> AV[Impaired Cell Growth/Production];

    D --> AW[Fur-Independent Gene Regulation];
    AW --> AX[Alternative Sigma Factors (e.g., Sigma E)];
    AX --> AY[Regulation of Outer Membrane Proteins & Virulence];
    AY --> AZ[Modulation of Iron Acquisition];

    L --> BA[/Repression of Iron Efflux Genes (e.g., fieF)/];
    O --> BB[/Derepression of Iron Efflux Genes/];
    BB --> BC[Iron Efflux Proteins & Export];
    BC --> B;

    U & X --> C1(AND: Cytoplasmic Iron Pool);
    C1 --> AH;


